  return values.reduce((accumulator, currentValue) => {
    return accumulator + currentValue;
  }, 0);
}

/**
 * Multiplies a number by the standard multiplier.
 * @param {number} inputValue - The value to multiply
 * @returns {number} The scaled result
 */
function scaleByMultiplier(inputValue) {
  const standardMultiplier = 2.5;
  return inputValue * standardMultiplier;
}

