    const response = await fetch(`${this.baseUrl}${endpoint}`, {
      method: 'POST',
      headers: this.headers,
      body: JSON.stringify(data)
    });

    return this.handleResponse(response);
  }

  // Method 3: Put endpoint (AI can suggest based on similar methods)
